<script setup lang="ts">import {ref} from 'vue'; import {useRouter} from 'vue-router'; import {api} from '../api/client'; const username=ref(''); const password=ref(''); const error=ref(''); const router=useRouter(); async function login(){try{await api.post('/auth/login',{username:username.value,password:password.value}); await router.push('/')}catch{error.value='用户名或密码错误'}}</script>
<template><main><h1>Bookshelf</h1><el-form @submit.prevent="login"><el-input v-model="username" placeholder="用户名"/><el-input v-model="password" type="password" show-password placeholder="密码"/><el-alert v-if="error" :title="error" type="error"/><el-button type="primary" native-type="submit">登录</el-button></el-form></main></template>
<style scoped>main{max-width:24rem;margin:15vh auto;padding:2rem}form{display:grid;gap:1rem}</style>
